exercises.expected_solution:
// 1. trade-events: key=userId
//    Reason: portfolio-service must process U01's trades in order.
//    All U01 trades → Partition 0 (always). Ordering guaranteed per user.

// 2. nse-tick-data: key=symbol
//    Reason: charting needs TCS ticks in time order.
//    All TCS ticks → Partition 1. Ordering preserved per stock.

// 3. audit-log: key=userId
//    Reason: auditors review per-user activity. Key=userId groups
//    one user's events together for efficient per-user queries.

// 4. notification-events: key=null (no key)
//    Reason: no ordering needed. Round-robin across partitions
//    for maximum throughput distribution.

// Example — 3 partitions, hash(key) % 3:
public class PartitionKeyExample {
    static int partition(String key, int numPartitions) {
        return Math.abs(key.hashCode()) % numPartitions;
    }
    public static void main(String[] args) {
        System.out.println("U01 → P" + partition("U01", 3));
        System.out.println("U02 → P" + partition("U02", 3));
        System.out.println("U01 (again) → P" + partition("U01", 3));  // same!
        System.out.println("TCS → P" + partition("TCS", 3));
        System.out.println("INFY → P" + partition("INFY", 3));
    }
}

