// ── RETENTION DIAGRAM ────────────────────────────────────────────
// Day 1:  [0][1][2]...[1000] messages
// Day 3:  [0][1]...[5000] messages | notification-svc crashes at offset 5000
// Day 5:  [0][1]...[7500] messages | notification-svc restarts
//         → resumes from offset 5001 (committed offset saved in Kafka)
//         → catches up: processes 5001-7500 (2500 messages)
// Day 6:  [0][1]...[9000] messages | tax-svc starts with --from-beginning
//         → reads from offset 0: ALL 9000 messages (full history)
// Day 10: messages from Day 1-3 (offsets 0-3000) DELETED by retention
//         → notification-svc: fine (already processed them, at offset 9000+)
//         → if tax-svc hadn't caught up, it would LOSE days 1-3

// Answer to each question:
// 2. notification-svc crashes at offset 5000 (Kafka has committed this)
// 3. Restarts at offset 5001 — the committed offset is persisted in Kafka
//    (stored in __consumer_offsets internal topic)
// 4. tax-svc with --from-beginning: starts at offset 0, reads all available
// 5. Day 10: offsets 0-~3000 (Day 1-3 messages) deleted by 7-day retention
//    notification-svc is fine — it processed them before deletion
//    tax-svc: if it hadn't reached offset 3000 by day 10, those messages are GONE

public class OffsetExplanation {
    // Kafka stores committed offsets in: __consumer_offsets topic
    // Consumer group = 'notification-svc'
    // Committed offset = last successfully processed offset + 1
    // On restart: consumer reads committed offset from __consumer_offsets
    // and resumes from there — no message loss (if within retention period)
    public static void main(String[] args) {
        System.out.println("Committed offset 5000 → restart from 5001");
        System.out.println("--from-beginning → offset 0 for that consumer group");
        System.out.println("After retention expires: messages gone, offset still valid");
    }
}

// Topic naming convention: {domain}.{entity}.{action}s (dot-separated)
// Examples:
// payment.transaction.events    (payment domain, transaction entity)
// payment.refund.events
// user.account.events
// merchant.settlement.events

// Base event schema (all events extend/include):
record KafkaEvent<T>(
    String eventId,       // UUID — for idempotency (deduplication)
    String eventType,     // e.g., 'PAYMENT_CAPTURED', 'REFUND_INITIATED'
    String sourceService, // e.g., 'payment-service'
    java.time.Instant timestamp,
    String traceId,       // distributed tracing correlation
    T payload             // domain-specific data
) {}

// Concrete events:
record PaymentPayload(String paymentId, double amount, String currency, String merchantId) {}
record RefundPayload(String refundId, String paymentId, double amount, String reason) {}
record AccountPayload(String userId, String eventType, java.util.Map<String,Object> changes) {}

