public class KafkaThroughputCalc {
    public static void main(String[] args) {
        // ── TRADE-EVENTS ──────────────────────────────────────────
        int tradesPerHour = 50_000;
        double processingTimeMs = 10.0;  // 10ms per notification

        // Throughput per consumer instance:
        // 1 second / 10ms = 100 messages/second
        // 100 * 3600 = 360,000 messages/hour per consumer
        double messagesPerSecondPerConsumer = 1000.0 / processingTimeMs;
        double messagesPerHourPerConsumer = messagesPerSecondPerConsumer * 3600;

        // Consumers needed:
        int consumersNeeded = (int) Math.ceil(tradesPerHour / messagesPerHourPerConsumer);
        System.out.println("=== TRADE-EVENTS ===");
        System.out.printf("Throughput/consumer: %.0f msg/hr%n", messagesPerHourPerConsumer);
        System.out.printf("Consumers needed: %d%n", consumersNeeded);
        System.out.printf("Partitions needed: %d (at least equal to consumers)%n%n",
            Math.max(consumersNeeded, 3));  // min 3 for replication/HA

        // ── MARKET-TICKS ──────────────────────────────────────────
        int ticksPerHour = 5_000_000;
        double tickProcessingMs = 2.0;

        double tickPerSecondPerConsumer = 1000.0 / tickProcessingMs;
        double tickPerHourPerConsumer = tickPerSecondPerConsumer * 3600;
        int tickConsumersNeeded = (int) Math.ceil(ticksPerHour / tickPerHourPerConsumer);

        System.out.println("=== MARKET-TICKS ===");
        System.out.printf("Throughput/consumer: %.0f ticks/hr%n", tickPerHourPerConsumer);
        System.out.printf("Consumers needed: %d%n", tickConsumersNeeded);
        System.out.printf("Partitions needed: %d (round up to 4 for clean assignment)%n",
            Math.max(tickConsumersNeeded, 4));
    }
}

import org.springframework.stereotype.Service;

// ── BEFORE: All synchronous (slow, brittle) ──────────────────────
class OrderServiceBefore {
    RestaurantClient restaurantClient;
    PaymentClient paymentClient;
    NotificationClient notificationClient;  // slow, might fail
    AnalyticsClient analyticsClient;         // slow, might fail
    PortfolioClient portfolioClient;          // slow, might fail

    Order placeOrder(OrderRequest req) {
        // Must wait for ALL of these:
        restaurantClient.checkAvailability(req);  // ~100ms — MUST wait
        paymentClient.charge(req);                // ~200ms — MUST wait
        notificationClient.sendSms(req);          // ~150ms — DON'T need to wait
        analyticsClient.logEvent(req);            // ~100ms — DON'T need to wait
        portfolioClient.update(req);              // ~80ms  — DON'T need to wait
        // Total: 630ms — user waits for ALL
        // Risk: if notificationClient down → ORDER FAILS!
    }
}

// ── AFTER: Hybrid — sync critical path, Kafka for side effects ───
@Service
class OrderServiceAfter {
    RestaurantClient restaurantClient;    // SYNC — must know if open
    PaymentClient paymentClient;           // SYNC — must succeed before confirming
    KafkaTemplate<String, Object> kafka;   // ASYNC — side effects via Kafka

    Order placeOrder(OrderRequest req) {
        // SYNC: critical path — need answers to proceed:
        restaurantClient.checkAvailability(req);  // ~100ms SYNC
        paymentClient.charge(req);                // ~200ms SYNC

        // Save order:
        Order saved = orderRepo.save(req);        // ~20ms

        // ASYNC: publish ONE event — all side effects listen:
        kafka.send("order-events", req.userId(),
            new OrderEvent(saved.id(), req.restaurantId(), "PLACED"));
        // ↑ 5ms — publish and return!

        return saved;  // Total: ~325ms (vs 630ms before)

        // notification-svc consumes order-events → sends SMS
        // analytics-svc consumes order-events → logs event
        // portfolio-svc consumes order-events → updates holdings
        // All happen AFTER the response, in parallel, independent
    }
}

