import java.util.*;

public class MessageSystemAdvisor {
    enum Throughput { HIGH, MEDIUM, LOW }
    enum Recommendation { KAFKA, RABBITMQ }

    record Requirements(
        Throughput throughput,
        boolean orderingRequired,
        boolean replayNeeded,
        boolean multipleConsumers
    ) {}

    public static String recommend(Requirements req) {
        boolean preferKafka = false;
        List<String> reasons = new ArrayList<>();

        if (req.throughput() == Throughput.HIGH) { preferKafka = true; reasons.add("High throughput → Kafka handles millions/sec"); }
        if (req.replayNeeded()) { preferKafka = true; reasons.add("Replay needed → Kafka retains messages (RabbitMQ deletes after ack)"); }
        if (req.multipleConsumers()) { preferKafka = true; reasons.add("Multiple consumers → Kafka consumer groups; RabbitMQ needs queue per consumer"); }
        if (!req.orderingRequired()) { /* both work */ }

        String system = preferKafka ? "KAFKA" : "RABBITMQ";
        if (!preferKafka) reasons.add("Low throughput, single consumer, no replay → RabbitMQ simpler");

        return system + ": " + String.join(" | ", reasons);
    }

    public static void main(String[] args) {
        // Audit logs:
        System.out.println("Audit logs: " + recommend(new Requirements(Throughput.MEDIUM, true, true, true)));
        // Notification queue:
        System.out.println("Notifications: " + recommend(new Requirements(Throughput.HIGH, false, false, true)));
        // Trade events:
        System.out.println("Trade events: " + recommend(new Requirements(Throughput.HIGH, true, true, true)));
        // Simple task queue:
        System.out.println("Task queue: " + recommend(new Requirements(Throughput.LOW, false, false, false)));
    }
}

