// ── THROUGHPUT CALCULATION ────────────────────────────────────────
class ThroughputCalc {
    static void calculate() {
        int tradesPerHour = 100_000;
        double processingMs = 5.0;
        double msgPerSecPerConsumer = 1000.0 / processingMs;  // 200 msg/s
        double msgPerHourPerConsumer = msgPerSecPerConsumer * 3600;  // 720,000
        int consumersNeeded = (int) Math.ceil(tradesPerHour / msgPerHourPerConsumer); // 1
        System.out.printf("trade-events: %d consumers needed, %d partitions minimum%n",
            consumersNeeded, Math.max(consumersNeeded * 2, 6));  // 2x headroom
    }
}

// ── HYBRID ARCHITECTURE ───────────────────────────────────────────
class ZerodhaArchitecture {
    /*
    SYNC (REST/Feign — critical path, blocking):
      order-svc → market-svc: GET current stock price
      order-svc → account-svc: Verify margin & account status
      order-svc → risk-svc: Check position limits

    ASYNC (Kafka — side effects, non-blocking):
      trade executed → zerodha.trade.events
        ← portfolio-svc: update holdings
        ← notification-svc: SMS 'TCS bought at ₹3890'
        ← analytics-svc: update dashboards
        ← tax-svc: calculate tax impact
        ← audit-svc: compliance log

    Result: trade API: ~120ms (3 sync calls)
            Side effects: async in parallel
    */
}

